import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def collaborative_cost(index, current_pos, all_positions, time_to_arrive):
        # Computes additional delay caused if any other truck can reach the target first
        min_other_time = float('inf')
        for pos in all_positions:
            if np.array_equal(pos, current_pos):
                continue
            other_time_to_arrive = calculate_distance(pos, unvisited_customers[index]) / truck_speed + current_time
            if other_time_to_arrive < time_to_arrive:
                min_other_time = min(min_other_time, other_time_to_arrive)
        return max(0, time_to_arrive - min_other_time)  # Cost increases when another truck can get there considerably sooner

    best_node = None
    min_overall_cost = float('inf')

    for i, customer in enumerate(unvisited_customers):
        travel_time = calculate_distance(cur_truck_pos, customer) / truck_speed
        arrival_time = current_time + travel_time
        window_open, window_close = time_windows[i]

        if arrival_time > window_close:
            penalty_time = (arrival_time - window_close)**2
        elif arrival_time < window_open:
            penalty_time = (window_open - arrival_time)**2
        else:
            penalty_time = -10  # Bonus for perfect timing

        collaborative_penalty = collaborative_cost(i, cur_truck_pos, all_truck_pos, arrival_time)

        overall_cost = travel_time + penalty_time + collaborative_penalty

        if overall_cost < min_overall_cost:
            min_overall_cost = overall_cost
            best_node = i

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(p1, p2):
        return np.linalg.norm(p2 - p1) / truck_speed

    def time_window_penalty(visit_time, time_window):
        start, end = time_window
        if visit_time < start:
            return (start - visit_time) * 0.4  # Lower penalty for being slightly early
        elif visit_time > end:
            return (visit_time - end) * 20  # Higher penalty for missing the window
        else:
            return -15  # Higher reward for precise timing

    def calculate_proximity_to_depot(position):
        return np.linalg.norm(depot_pos - position)  # Added to encourage routes that keep trucks nearer to the depot

    best_cost = float('inf')
    best_node = None

    for index, customer in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer)
        arrival_time = current_time + travel_time
        penalty = time_window_penalty(arrival_time, time_windows[index])
        proximity_penalty = calculate_proximity_to_depot(customer) / 100  # Ensure proximity effect is balanced
        cost = (travel_time * 0.9 + penalty + proximity_penalty)  # Adjust weights to prioritize travel time slightly lower and proximity slightly

        if cost < best_cost:
            best_cost = cost
            best_node = index

    return best_node

import numpy as np
import heapq

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    def time_to_reach(start, end):
        return distance(start, end) / truck_speed

    def is_within_time_window(arrival_time, window):
        return window[0] <= arrival_time <= window[1]

    reachable_customers = []
    heapq.heapify(reachable_customers)

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = time_to_reach(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel_time
        time_window = time_windows[i]

        # Priority by start of time window, distance, and if within time window
        if is_within_time_window(arrival_time, time_window):
            urgency = 0
        else:
            urgency = min(abs(arrival_time - time_window[0]), abs(arrival_time - time_window[1]))

        heapq.heappush(reachable_customers, (urgency, travel_time, i))

    # Choose the most urgent customer that can be realistically reached
    while reachable_customers:
        _, _, customer_index = heapq.heappop(reachable_customers)
        estimated_arrival = current_time + time_to_reach(cur_truck_pos, unvisited_customers[customer_index])
        if is_within_time_window(estimated_arrival, time_windows[customer_index]):
            best_node = customer_index
            break
    else:
        best_node = None  # No viable customer could be reached: better wait at current position

    return best_node
